(function (global) {
  function clamp(value, min, max) {
    return Math.max(min, Math.min(max, value));
  }

  function hexToRgba(hex, alpha) {
    if (!hex || hex[0] !== "#") {
      return hex || "rgba(255,255,255," + alpha + ")";
    }
    var normalized = hex.length === 4
      ? "#" + hex[1] + hex[1] + hex[2] + hex[2] + hex[3] + hex[3]
      : hex;
    var value = parseInt(normalized.slice(1), 16);
    var r = (value >> 16) & 255;
    var g = (value >> 8) & 255;
    var b = value & 255;
    return "rgba(" + r + "," + g + "," + b + "," + alpha + ")";
  }

  function Chart(context, config) {
    this.ctx = context;
    this.canvas = context.canvas;
    this.config = config || {};
    this.resizeObserver = null;
    this.render = this.render.bind(this);
    if (typeof ResizeObserver !== "undefined") {
      this.resizeObserver = new ResizeObserver(this.render);
      this.resizeObserver.observe(this.canvas);
    }
    this.render();
  }

  Chart.prototype.destroy = function () {
    if (this.resizeObserver) {
      this.resizeObserver.disconnect();
    }
    this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);
  };

  Chart.prototype.render = function () {
    var parentWidth = this.canvas.parentElement ? this.canvas.parentElement.clientWidth : 640;
    var width = Math.max(320, parentWidth);
    var height = this.canvas.dataset.height ? parseInt(this.canvas.dataset.height, 10) : 250;
    if (this.canvas.width !== width) {
      this.canvas.width = width;
    }
    if (this.canvas.height !== height) {
      this.canvas.height = height;
    }

    var type = this.config.type || "bar";
    this.ctx.clearRect(0, 0, width, height);
    if (type === "doughnut") {
      this.drawDoughnut(width, height);
      return;
    }
    this.drawBars(width, height);
  };

  Chart.prototype.drawBars = function (width, height) {
    var ctx = this.ctx;
    var dataset = (this.config.data.datasets || [])[0] || { data: [], backgroundColor: "#56c7ff" };
    var labels = this.config.data.labels || [];
    var values = dataset.data || [];
    var margin = { top: 18, right: 18, bottom: 40, left: 18 };
    var innerWidth = width - margin.left - margin.right;
    var innerHeight = height - margin.top - margin.bottom;
    var maxValue = Math.max.apply(Math, values.concat([1]));
    var count = Math.max(values.length, 1);
    var gap = 10;
    var barWidth = (innerWidth - gap * (count - 1)) / count;

    ctx.strokeStyle = "rgba(255,255,255,0.08)";
    ctx.lineWidth = 1;
    for (var i = 0; i < 4; i += 1) {
      var y = margin.top + (innerHeight / 3) * i;
      ctx.beginPath();
      ctx.moveTo(margin.left, y);
      ctx.lineTo(width - margin.right, y);
      ctx.stroke();
    }

    values.forEach(function (value, index) {
      var x = margin.left + index * (barWidth + gap);
      var barHeight = innerHeight * (value / maxValue);
      var y = margin.top + innerHeight - barHeight;
      var color = Array.isArray(dataset.backgroundColor)
        ? dataset.backgroundColor[index % dataset.backgroundColor.length]
        : dataset.backgroundColor;
      var gradient = ctx.createLinearGradient(0, y, 0, margin.top + innerHeight);
      gradient.addColorStop(0, color || "#56c7ff");
      gradient.addColorStop(1, hexToRgba(color || "#56c7ff", 0.15));

      ctx.fillStyle = gradient;
      var radius = clamp(barWidth / 6, 4, 10);
      ctx.beginPath();
      ctx.moveTo(x, margin.top + innerHeight);
      ctx.lineTo(x, y + radius);
      ctx.quadraticCurveTo(x, y, x + radius, y);
      ctx.lineTo(x + barWidth - radius, y);
      ctx.quadraticCurveTo(x + barWidth, y, x + barWidth, y + radius);
      ctx.lineTo(x + barWidth, margin.top + innerHeight);
      ctx.closePath();
      ctx.fill();

      ctx.fillStyle = "rgba(238,243,246,0.8)";
      ctx.font = "12px Avenir Next, sans-serif";
      ctx.textAlign = "center";
      ctx.fillText(String(value), x + barWidth / 2, Math.max(y - 8, 14));
      ctx.fillStyle = "rgba(150,166,181,0.85)";
      ctx.fillText(labels[index] || "", x + barWidth / 2, height - 14);
    });
  };

  Chart.prototype.drawDoughnut = function (width, height) {
    var ctx = this.ctx;
    var dataset = (this.config.data.datasets || [])[0] || { data: [], backgroundColor: [] };
    var values = dataset.data || [];
    var labels = this.config.data.labels || [];
    var colors = dataset.backgroundColor || [];
    var total = values.reduce(function (sum, value) { return sum + value; }, 0);
    var centerX = width * 0.36;
    var centerY = height * 0.5;
    var radius = Math.min(width, height) * 0.24;
    var lineWidth = radius * 0.48;
    var cursor = -Math.PI / 2;

    ctx.lineWidth = lineWidth;
    values.forEach(function (value, index) {
      var slice = total === 0 ? (Math.PI * 2) / Math.max(values.length, 1) : (value / total) * Math.PI * 2;
      ctx.strokeStyle = colors[index % colors.length] || "#56c7ff";
      ctx.beginPath();
      ctx.arc(centerX, centerY, radius, cursor, cursor + slice);
      ctx.stroke();
      cursor += slice;
    });

    ctx.fillStyle = "rgba(238,243,246,0.9)";
    ctx.font = "700 20px Iowan Old Style, serif";
    ctx.textAlign = "center";
    ctx.fillText(String(total), centerX, centerY + 7);
    ctx.font = "12px Avenir Next, sans-serif";
    ctx.fillStyle = "rgba(150,166,181,0.82)";
    ctx.fillText("total", centerX, centerY + 26);

    var legendX = width * 0.64;
    labels.forEach(function (label, index) {
      var y = 34 + index * 26;
      ctx.fillStyle = colors[index % colors.length] || "#56c7ff";
      ctx.beginPath();
      ctx.arc(legendX, y, 6, 0, Math.PI * 2);
      ctx.fill();
      ctx.fillStyle = "rgba(238,243,246,0.9)";
      ctx.textAlign = "left";
      ctx.fillText(label + " (" + values[index] + ")", legendX + 14, y + 4);
    });
  };

  global.Chart = Chart;
})(window);
